#include <bits/stdc++.h>
using namespace std;
int main(){
    string A,B;
    int len,a[501]={0},b[501]={0},c[501]={0};
    cin>>A>>B;
    for (int i=A.length()-1;i>=0;i--){
        a[A.length()-1-i]=A[i]-'0';
    }
    for (int i=B.length()-1;i>=0;i--){
        b[B.length()-1-i]=B[i]-'0';
    }
    if (A.length()>B.length()) len=A.length();
    else len=B.length();
    for (int i=0;i<len;i++){
        c[i]=c[i]+a[i]+b[i];
        if (c[i]>=10){
            c[i]=c[i]-10;
            c[i+1]+=1;
        }  
    }
    if (c[len]!=0) len++;
    for (int i=len-1;i>=0;i--){
        cout<<c[i];
    }
    return 0;
}
